import{_ as e,o as l,c as d,a2 as a}from"./chunks/framework.Pywvta2k.js";const o=JSON.parse('{"title":"药性本草速查","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/06-跨病证索引/06-药性本草.md","filePath":"tcm-data/06-跨病证索引/06-药性本草.md","lastUpdated":1781084559000}'),n={name:"tcm-data/06-跨病证索引/06-药性本草.md"};function g(s,t,i,x,r,y){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="药性本草速查" tabindex="-1">药性本草速查 <a class="header-anchor" href="#药性本草速查" aria-label="Permalink to &quot;药性本草速查&quot;">​</a></h1><blockquote><p>按功能分类，跨医家，附归经与常用剂量 ⭐ = 普光/普明处方中使用的药物</p></blockquote><hr><h2 id="一、补气药" tabindex="-1">一、补气药 <a class="header-anchor" href="#一、补气药" aria-label="Permalink to &quot;一、补气药&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">性味</th><th style="text-align:left;">归经</th><th style="text-align:left;">功效</th><th style="text-align:left;">⭐剂量</th></tr></thead><tbody><tr><td style="text-align:left;">⭐<strong>人参</strong></td><td style="text-align:left;">甘，微寒</td><td style="text-align:left;">脾、肺</td><td style="text-align:left;">大补元气，补脾益肺</td><td style="text-align:left;">6-15g</td></tr><tr><td style="text-align:left;"><strong>黄芪</strong></td><td style="text-align:left;">甘，温</td><td style="text-align:left;">脾、肺</td><td style="text-align:left;">补气升阳，固表止汗</td><td style="text-align:left;">15-60g</td></tr><tr><td style="text-align:left;">⭐<strong>炙甘草</strong></td><td style="text-align:left;">甘，平</td><td style="text-align:left;">心、肺、脾、胃</td><td style="text-align:left;">补脾益气，调和诸药</td><td style="text-align:left;">3-15g</td></tr><tr><td style="text-align:left;"><strong>白术</strong></td><td style="text-align:left;">甘，温</td><td style="text-align:left;">脾、胃</td><td style="text-align:left;">健脾益气，燥湿</td><td style="text-align:left;">9-30g</td></tr><tr><td style="text-align:left;"><strong>山药</strong></td><td style="text-align:left;">甘，平</td><td style="text-align:left;">脾、肺、肾</td><td style="text-align:left;">补脾养肺，固肾</td><td style="text-align:left;">15-30g</td></tr><tr><td style="text-align:left;"><strong>大枣</strong></td><td style="text-align:left;">甘，温</td><td style="text-align:left;">脾、胃</td><td style="text-align:left;">补中益气，养血安神</td><td style="text-align:left;">3-12枚</td></tr></tbody></table><hr><h2 id="二、温里药" tabindex="-1">二、温里药 <a class="header-anchor" href="#二、温里药" aria-label="Permalink to &quot;二、温里药&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">性味</th><th style="text-align:left;">归经</th><th style="text-align:left;">功效</th><th style="text-align:left;">⭐剂量</th></tr></thead><tbody><tr><td style="text-align:left;">⭐<strong>制附子</strong></td><td style="text-align:left;">辛，大热，有毒</td><td style="text-align:left;">心、肾、脾</td><td style="text-align:left;">回阳救逆，补火助阳</td><td style="text-align:left;">6-30g（先煎）</td></tr><tr><td style="text-align:left;">⭐<strong>干姜</strong></td><td style="text-align:left;">辛，热</td><td style="text-align:left;">脾、胃、心、肺</td><td style="text-align:left;">温中散寒，回阳通脉</td><td style="text-align:left;">6-15g</td></tr><tr><td style="text-align:left;">⭐<strong>桂枝</strong></td><td style="text-align:left;">辛、甘，温</td><td style="text-align:left;">心、肺、膀胱</td><td style="text-align:left;">发汗解肌，温通经脉</td><td style="text-align:left;">6-15g</td></tr><tr><td style="text-align:left;"><strong>肉桂</strong></td><td style="text-align:left;">辛、甘，大热</td><td style="text-align:left;">肾、脾、心、肝</td><td style="text-align:left;">补火助阳，引火归原</td><td style="text-align:left;">3-10g</td></tr><tr><td style="text-align:left;"><strong>吴茱萸</strong></td><td style="text-align:left;">辛、苦，热</td><td style="text-align:left;">肝、脾、胃</td><td style="text-align:left;">散寒止痛，降逆</td><td style="text-align:left;">3-9g</td></tr></tbody></table><hr><h2 id="三、清热药" tabindex="-1">三、清热药 <a class="header-anchor" href="#三、清热药" aria-label="Permalink to &quot;三、清热药&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">性味</th><th style="text-align:left;">归经</th><th style="text-align:left;">功效</th><th style="text-align:left;">⭐剂量</th></tr></thead><tbody><tr><td style="text-align:left;">⭐<strong>黄柏</strong></td><td style="text-align:left;">苦，寒</td><td style="text-align:left;">肾、膀胱</td><td style="text-align:left;">清热燥湿，泻火除蒸</td><td style="text-align:left;">3-9g</td></tr><tr><td style="text-align:left;"><strong>黄连</strong></td><td style="text-align:left;">苦，寒</td><td style="text-align:left;">心、脾、胃、肝</td><td style="text-align:left;">清热燥湿，泻火解毒</td><td style="text-align:left;">3-9g</td></tr><tr><td style="text-align:left;"><strong>黄芩</strong></td><td style="text-align:left;">苦，寒</td><td style="text-align:left;">肺、胆、胃、大肠</td><td style="text-align:left;">清热燥湿，泻火解毒</td><td style="text-align:left;">6-15g</td></tr><tr><td style="text-align:left;"><strong>石膏</strong></td><td style="text-align:left;">辛、甘，大寒</td><td style="text-align:left;">肺、胃</td><td style="text-align:left;">清热泻火，除烦止渴</td><td style="text-align:left;">15-60g</td></tr><tr><td style="text-align:left;"><strong>知母</strong></td><td style="text-align:left;">苦、甘，寒</td><td style="text-align:left;">肺、胃、肾</td><td style="text-align:left;">清热泻火，滋阴润燥</td><td style="text-align:left;">6-15g</td></tr><tr><td style="text-align:left;"><strong>生地</strong></td><td style="text-align:left;">甘、苦，寒</td><td style="text-align:left;">心、肝、肾</td><td style="text-align:left;">清热凉血，养阴生津</td><td style="text-align:left;">10-30g</td></tr><tr><td style="text-align:left;">⭐<strong>丹皮</strong></td><td style="text-align:left;">苦、辛，微寒</td><td style="text-align:left;">心、肝、肾</td><td style="text-align:left;">清热凉血，活血散瘀</td><td style="text-align:left;">6-15g</td></tr><tr><td style="text-align:left;"><strong>地骨皮</strong></td><td style="text-align:left;">甘，寒</td><td style="text-align:left;">肺、肝、肾</td><td style="text-align:left;">凉血除蒸，清肺降火</td><td style="text-align:left;">9-15g</td></tr></tbody></table><hr><h2 id="四、祛湿药" tabindex="-1">四、祛湿药 <a class="header-anchor" href="#四、祛湿药" aria-label="Permalink to &quot;四、祛湿药&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">性味</th><th style="text-align:left;">归经</th><th style="text-align:left;">功效</th><th style="text-align:left;">⭐剂量</th></tr></thead><tbody><tr><td style="text-align:left;">⭐<strong>茯苓</strong></td><td style="text-align:left;">甘、淡，平</td><td style="text-align:left;">心、脾、肺、肾</td><td style="text-align:left;">利水渗湿，健脾</td><td style="text-align:left;">10-30g</td></tr><tr><td style="text-align:left;">⭐<strong>泽泻</strong></td><td style="text-align:left;">甘，寒</td><td style="text-align:left;">肾、膀胱</td><td style="text-align:left;">利水渗湿，泄热</td><td style="text-align:left;">6-15g</td></tr><tr><td style="text-align:left;"><strong>猪苓</strong></td><td style="text-align:left;">甘、淡，平</td><td style="text-align:left;">肾、膀胱</td><td style="text-align:left;">利水渗湿</td><td style="text-align:left;">6-15g</td></tr><tr><td style="text-align:left;"><strong>薏苡仁</strong></td><td style="text-align:left;">甘、淡，微寒</td><td style="text-align:left;">脾、胃、肺</td><td style="text-align:left;">利水渗湿，健脾止泻</td><td style="text-align:left;">15-30g</td></tr><tr><td style="text-align:left;"><strong>滑石</strong></td><td style="text-align:left;">甘、淡，寒</td><td style="text-align:left;">膀胱、肺、胃</td><td style="text-align:left;">利尿通淋，清热解暑</td><td style="text-align:left;">9-30g</td></tr></tbody></table><hr><h2 id="五、养血活血药" tabindex="-1">五、养血活血药 <a class="header-anchor" href="#五、养血活血药" aria-label="Permalink to &quot;五、养血活血药&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">性味</th><th style="text-align:left;">归经</th><th style="text-align:left;">功效</th><th style="text-align:left;">⭐剂量</th></tr></thead><tbody><tr><td style="text-align:left;">⭐<strong>当归</strong></td><td style="text-align:left;">甘、辛，温</td><td style="text-align:left;">肝、心、脾</td><td style="text-align:left;">补血活血，调经止痛</td><td style="text-align:left;">6-15g</td></tr><tr><td style="text-align:left;">⭐<strong>白芍</strong></td><td style="text-align:left;">苦、酸，微寒</td><td style="text-align:left;">肝、脾</td><td style="text-align:left;">养血柔肝，缓中止痛</td><td style="text-align:left;">6-20g</td></tr><tr><td style="text-align:left;">⭐<strong>制首乌</strong></td><td style="text-align:left;">甘、涩，微温</td><td style="text-align:left;">肝、肾</td><td style="text-align:left;">补肝肾，益精血，乌须发</td><td style="text-align:left;">10-20g</td></tr><tr><td style="text-align:left;"><strong>熟地</strong></td><td style="text-align:left;">甘，微温</td><td style="text-align:left;">肝、肾</td><td style="text-align:left;">滋阴补血，益精填髓</td><td style="text-align:left;">10-30g</td></tr><tr><td style="text-align:left;"><strong>川芎</strong></td><td style="text-align:left;">辛，温</td><td style="text-align:left;">肝、胆、心包</td><td style="text-align:left;">活血行气，祛风止痛</td><td style="text-align:left;">6-12g</td></tr><tr><td style="text-align:left;"><strong>桃仁</strong></td><td style="text-align:left;">苦、甘，平</td><td style="text-align:left;">心、肝、大肠</td><td style="text-align:left;">活血祛瘀，润肠通便</td><td style="text-align:left;">6-15g</td></tr><tr><td style="text-align:left;"><strong>红花</strong></td><td style="text-align:left;">辛，温</td><td style="text-align:left;">心、肝</td><td style="text-align:left;">活血通经，散瘀止痛</td><td style="text-align:left;">3-10g</td></tr></tbody></table><hr><h2 id="六、潜阳安神药" tabindex="-1">六、潜阳安神药 <a class="header-anchor" href="#六、潜阳安神药" aria-label="Permalink to &quot;六、潜阳安神药&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">性味</th><th style="text-align:left;">归经</th><th style="text-align:left;">功效</th><th style="text-align:left;">⭐剂量</th></tr></thead><tbody><tr><td style="text-align:left;">⭐<strong>生龙骨</strong></td><td style="text-align:left;">甘、涩，平</td><td style="text-align:left;">心、肝、肾</td><td style="text-align:left;">镇惊安神，平肝潜阳</td><td style="text-align:left;">15-30g（先煎）</td></tr><tr><td style="text-align:left;">⭐<strong>生牡蛎</strong></td><td style="text-align:left;">咸，微寒</td><td style="text-align:left;">肝、胆、肾</td><td style="text-align:left;">潜阳补阴，软坚散结</td><td style="text-align:left;">15-30g（先煎）</td></tr><tr><td style="text-align:left;"><strong>酸枣仁</strong></td><td style="text-align:left;">甘、酸，平</td><td style="text-align:left;">肝、胆、心</td><td style="text-align:left;">养心安神，敛汗</td><td style="text-align:left;">10-20g</td></tr><tr><td style="text-align:left;"><strong>五味子</strong></td><td style="text-align:left;">酸、甘，温</td><td style="text-align:left;">肺、心、肾</td><td style="text-align:left;">收敛固涩，益气生津</td><td style="text-align:left;">3-9g</td></tr><tr><td style="text-align:left;"><strong>磁石</strong></td><td style="text-align:left;">咸，寒</td><td style="text-align:left;">心、肝、肾</td><td style="text-align:left;">镇惊安神，平肝潜阳</td><td style="text-align:left;">15-30g</td></tr><tr><td style="text-align:left;"><strong>代赭石</strong></td><td style="text-align:left;">苦，寒</td><td style="text-align:left;">肝、心包</td><td style="text-align:left;">平肝潜阳，降逆</td><td style="text-align:left;">15-30g</td></tr></tbody></table><hr><h2 id="七、化痰降气药" tabindex="-1">七、化痰降气药 <a class="header-anchor" href="#七、化痰降气药" aria-label="Permalink to &quot;七、化痰降气药&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">性味</th><th style="text-align:left;">归经</th><th style="text-align:left;">功效</th><th style="text-align:left;">⭐剂量</th></tr></thead><tbody><tr><td style="text-align:left;">⭐<strong>半夏</strong></td><td style="text-align:left;">辛，温，有毒</td><td style="text-align:left;">脾、胃、肺</td><td style="text-align:left;">燥湿化痰，降逆止呕</td><td style="text-align:left;">6-12g</td></tr><tr><td style="text-align:left;"><strong>陈皮</strong></td><td style="text-align:left;">辛、苦，温</td><td style="text-align:left;">脾、肺</td><td style="text-align:left;">理气健脾，燥湿化痰</td><td style="text-align:left;">6-12g</td></tr><tr><td style="text-align:left;">⭐<strong>麦冬</strong></td><td style="text-align:left;">甘、微苦，微寒</td><td style="text-align:left;">心、肺、胃</td><td style="text-align:left;">养阴润肺，清心除烦</td><td style="text-align:left;">9-15g</td></tr><tr><td style="text-align:left;"><strong>杏仁</strong></td><td style="text-align:left;">苦，微温，有小毒</td><td style="text-align:left;">肺、大肠</td><td style="text-align:left;">止咳平喘，润肠通便</td><td style="text-align:left;">6-12g</td></tr></tbody></table><hr><h2 id="八、引经与升降药" tabindex="-1">八、引经与升降药 <a class="header-anchor" href="#八、引经与升降药" aria-label="Permalink to &quot;八、引经与升降药&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">功用</th><th style="text-align:left;">⭐剂量</th></tr></thead><tbody><tr><td style="text-align:left;">⭐<strong>怀牛膝</strong></td><td style="text-align:left;">引火下行，补肝肾，强腰膝</td><td style="text-align:left;">6-15g</td></tr><tr><td style="text-align:left;"><strong>柴胡</strong></td><td style="text-align:left;">疏肝升阳（少量升，大量散）</td><td style="text-align:left;">3-6g（升），9-15g（散）</td></tr><tr><td style="text-align:left;"><strong>升麻</strong></td><td style="text-align:left;">升阳举陷</td><td style="text-align:left;">3-9g</td></tr><tr><td style="text-align:left;"><strong>桔梗</strong></td><td style="text-align:left;">载药上行（引经）</td><td style="text-align:left;">3-9g</td></tr></tbody></table><hr><h2 id="九、普光核心用药组速查" tabindex="-1">九、普光核心用药组速查 <a class="header-anchor" href="#九、普光核心用药组速查" aria-label="Permalink to &quot;九、普光核心用药组速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">用药组</th><th style="text-align:left;">药物</th><th style="text-align:left;">功能</th><th style="text-align:left;">对应病机</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>黄芽汤组</strong></td><td style="text-align:left;">人参+干姜+茯苓+炙甘草</td><td style="text-align:left;">运转中轴</td><td style="text-align:left;">中气虚寒、土湿</td></tr><tr><td style="text-align:left;"><strong>温阳组</strong></td><td style="text-align:left;">附子+干姜</td><td style="text-align:left;">温脾肾之阳</td><td style="text-align:left;">水寒</td></tr><tr><td style="text-align:left;"><strong>达木组</strong></td><td style="text-align:left;">桂枝+当归+首乌</td><td style="text-align:left;">升肝木、养肝血</td><td style="text-align:left;">木郁、血虚</td></tr><tr><td style="text-align:left;"><strong>潜降组</strong></td><td style="text-align:left;">龙骨+牡蛎+白芍</td><td style="text-align:left;">潜降相火</td><td style="text-align:left;">相火不降</td></tr><tr><td style="text-align:left;"><strong>清湿热组</strong></td><td style="text-align:left;">黄柏+泽泻+丹皮</td><td style="text-align:left;">清利湿热、活血</td><td style="text-align:left;">湿热下注</td></tr><tr><td style="text-align:left;"><strong>引经组</strong></td><td style="text-align:left;">牛膝</td><td style="text-align:left;">引火下行</td><td style="text-align:left;">上热</td></tr></tbody></table><h2 id="十、普明核心用药组速查" tabindex="-1">十、普明核心用药组速查 <a class="header-anchor" href="#十、普明核心用药组速查" aria-label="Permalink to &quot;十、普明核心用药组速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">用药组</th><th style="text-align:left;">药物</th><th style="text-align:left;">功能</th><th style="text-align:left;">对应病机</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>黄芽汤组（减干姜）</strong></td><td style="text-align:left;">人参+茯苓+炙甘草</td><td style="text-align:left;">运转中轴（无过热）</td><td style="text-align:left;">中气虚</td></tr><tr><td style="text-align:left;"><strong>养血组</strong></td><td style="text-align:left;">当归+白芍+熟地</td><td style="text-align:left;">养肝血、调经</td><td style="text-align:left;">血虚、月经先期</td></tr><tr><td style="text-align:left;"><strong>潜降组</strong></td><td style="text-align:left;">牡蛎+五味子+麦冬</td><td style="text-align:left;">敛浮火、生津</td><td style="text-align:left;">相火浮越</td></tr><tr><td style="text-align:left;"><strong>安神组</strong></td><td style="text-align:left;">酸枣仁+牡蛎</td><td style="text-align:left;">安神助眠</td><td style="text-align:left;">入睡困难</td></tr><tr><td style="text-align:left;"><strong>疏郁组</strong></td><td style="text-align:left;">柴胡</td><td style="text-align:left;">疏肝解郁</td><td style="text-align:left;">烦躁</td></tr><tr><td style="text-align:left;"><strong>健脾组</strong></td><td style="text-align:left;">白术+茯苓</td><td style="text-align:left;">健脾祛湿</td><td style="text-align:left;">腹胀、带多</td></tr><tr><td style="text-align:left;"><strong>固肾组</strong></td><td style="text-align:left;">杜仲</td><td style="text-align:left;">补肾强腰</td><td style="text-align:left;">腰凉</td></tr></tbody></table><hr><p><em>本索引可随数据库扩展持续增加。后续可做&quot;药对专题&quot;——经典药对（如桂枝+白芍、龙骨+牡蛎）的配伍原理。</em></p>',33)])])}const h=e(n,[["render",g]]);export{o as __pageData,h as default};
